	ps.Plans[planFile] = entry
	require.NoError(t, ps.Save())
	h.planState = ps
	h.planStateDir = plansDir
	h.fsm = newPlanFSMForTest(t, plansDir)
	h.activeRepoPath = dir
	h.updateSidebarPlans()
}

